    @Nullable
    private static SysSnapshot toSysSnapshot(SnapshotsInProgress.Entry entry) {
        if (entry == null) {
            return null;
        }
        var snapshot = entry.snapshot();
        var repository = entry.repository();
        if (repository == null) {
            return null;
        }
        var repositoryMetadata = repository.getMetadata();
        if (repositoryMetadata == null) {
            return null;
        }
        var repositoryName = repositoryMetadata.name();
        var snapshotId = snapshot.getSnapshotId();
        var tables = Lists.newArrayList();
        for (var indexId : entry.indices()) {
            var indexName = indexId.getName();
            if (indexName != null) {
                tables.add(indexName);
            }
        }
        return new SysSnapshot(
            snapshotId.getName(),
            repositoryName,
            tables,
            tables,
            entry.startTime(),
            0L,
            null,
            SnapshotState.IN_PROGRESS.name(),
            List.of()
        );
    }

